const fs = require('fs');

const parser = require('@babel/parser');

/**
 * @typedef {parser.ParseResult<import('@babel/types').File>} BabelAST
 */

class AstCache {
  /** @type {Map<string, BabelAST>} */
  #astMap;

  /** @type {parser.ParserOptions} */
  #parserOptions;

  constructor() {
    this.#astMap = new Map();
    this.#parserOptions = {
      plugins: ['jsx', 'typescript'],
      sourceType: 'module',
    };
  }

  clear() {
    this.#astMap.clear();
  }

  /**
   * @param {string} filePath
   */
  #parseFile(filePath) {
    const sourceCode = fs.readFileSync(filePath, 'utf-8');

    return parser.parse(sourceCode, this.#parserOptions);
  }

  /**
   * @param {string} filePath
   */
  getAstByFilePath(filePath) {
    const cachedAst = this.#astMap.get(filePath);

    if (cachedAst) {
      return cachedAst;
    }

    const ast = this.#parseFile(filePath);

    this.#astMap.set(filePath, ast);

    return ast;
  }
}

const astCache = new AstCache();

module.exports = {
  astCache,
};
